// ═══════ SMART COMPATIBILITY ═══════

export function getCompatible(category, currentBuild) {
  const items = COMPONENTS[category] || [];
  if (!currentBuild) return items.map(c => ({ ...c, compatible: true, reason: null }));

  return items.map(component => {
    const issues = [];

    if (category === 'motherboard' && currentBuild.cpu) {
      if (component.socket !== currentBuild.cpu.socket)
        issues.push(`سوكت ${component.socket} مو متوافق مع المعالج (${currentBuild.cpu.socket})`);
    }
    if (category === 'cpu' && currentBuild.motherboard) {
      if (component.socket !== currentBuild.motherboard.socket)
        issues.push(`سوكت ${component.socket} مو متوافق مع اللوحة (${currentBuild.motherboard.socket})`);
    }
    if (category === 'ram' && currentBuild.motherboard) {
      if (component.type !== currentBuild.motherboard.ramType)
        issues.push(`${component.type} مو متوافق مع اللوحة (${currentBuild.motherboard.ramType})`);
    }
    if (category === 'psu') {
      const needed = estimateWattage(currentBuild);
      if (component.watt < needed)
        issues.push(`${component.watt}W أقل من المطلوب (~${needed}W)`);
    }
    if (category === 'cooler' && currentBuild.cpu) {
      if (component.tdpMax < currentBuild.cpu.tdp)
        issues.push(`التبريد (${component.tdpMax}W max) ضعيف للمعالج (${currentBuild.cpu.tdp}W)`);
    }

    return { ...component, compatible: issues.length === 0, reason: issues.length > 0 ? issues[0] : null };
  });
}

// ═══════ WATTAGE CALCULATOR ═══════

export function estimateWattage(build) {
  let total = 50; // base
  if (build.cpu?.tdp) total += build.cpu.tdp;
  else if (build.cpu) total += 125; // assume 125W if unknown CPU
  if (build.gpu?.tdp) total += build.gpu.tdp;
  else if (build.gpu) total += 200; // assume 200W if unknown GPU
  if (build.ram) total += 10;
  if (build.ssd) total += 10;
  if (build.cooler) total += 15;
  return Math.ceil(total * 1.2);
}

export function getRecommendedPSU(build) {
  const needed = estimateWattage(build);
  if (needed <= 450) return 550;
  if (needed <= 550) return 650;
  if (needed <= 650) return 750;
  if (needed <= 750) return 850;
  if (needed <= 900) return 1000;
  if (needed <= 1100) return 1200;
  return 1500;
}

// ═══════ AMAZON PRODUCT IMAGES ═══════

export function getAmazonImageUrl(component) {
  if (!component) return null;
  if (component.image_url) return component.image_url;
  if (component.asin) {
    return `https://m.media-amazon.com/images/P/${component.asin}._AC_SL300_.jpg`;
  }
  return null;
}

// Higher-res version for larger displays
export function getAmazonImageUrlHQ(component) {
  if (!component) return null;
  if (component.image_url) return component.image_url;
  if (component.asin) {
    return `https://m.media-amazon.com/images/P/${component.asin}._AC_SL500_.jpg`;
  }
  return null;
}

// ═══════ AMAZON LINKS ═══════

export function getAmazonLink(component) {
  if (!component) return `https://www.amazon.sa/?tag=${TAG}`;
  if (component.asin) return `https://www.amazon.sa/dp/${component.asin}?tag=${TAG}`;
  const search = component.search || encodeURIComponent(component.name);
  return `https://www.amazon.sa/s?k=${search}&tag=${TAG}`;
}

export function getAmazonCartLink(components) {
  const names = Object.values(components).filter(Boolean).map(c => c.name).join(' ');
  return `https://www.amazon.sa/s?k=${encodeURIComponent(names)}&tag=${TAG}`;
}

// Get component by ID
export function getById(id) {
  for (const items of Object.values(COMPONENTS)) {
    const found = items.find(c => c.id === id);
    if (found) return found;
  }
  return null;
}

// Get all components flat
export function getAllComponents() {
  const all = [];
  for (const [type, items] of Object.entries(COMPONENTS))
    items.forEach(item => all.push({ ...item, type }));
  return all;
}

// Load preset build
export function loadPreset(presetKey) {
  const preset = PRESETS.find(p => p.key === presetKey);
  if (!preset) return {};
  const build = {};
  for (const [cat, id] of Object.entries(preset.build))
    build[cat] = getById(id);
  return build;
}

// Calculate total price
export function calcTotal(build) {
  return Object.values(build).reduce((sum, c) => sum + (c?.price || 0), 0);
}

// Rich display name — appends key specs not already in the name
const addSpec = (name, spec) => {
  if (!spec) return '';
  const s = String(spec);
  if (name.toLowerCase().includes(s.toLowerCase())) return '';
  return ` ${s}`;
};

export function getDisplayName(component, category) {
  if (!component) return '';
  const name = component.name || '';
  const cat = category || component.type || '';
  switch (cat) {
    case 'cpu': {
      const clock = component.boostClock ? `${component.boostClock} GHz` : '';
      const cores = component.cores ? `${component.cores}-Core` : '';
      return `${name}${addSpec(name, clock)}${addSpec(name, cores)}`.trim();
    }
    case 'gpu': {
      const vram = component.vram ? `${component.vram}GB` : '';
      return `${name}${addSpec(name, vram)}`.trim();
    }
    case 'motherboard': {
      const chipset = component.chipset || '';
      const ff = component.formFactor || '';
      const ddr = component.ramType || '';
      return `${name}${addSpec(name, chipset)}${addSpec(name, ff)}${addSpec(name, ddr)}`.trim();
    }
    case 'ram': {
      const size = component.size ? `${component.size}GB` : '';
      const type = component.type || '';
      const speed = component.speed ? `${component.speed}MHz` : '';
      return `${name}${addSpec(name, size)}${addSpec(name, type)}${addSpec(name, speed)}`.trim();
    }
    case 'ssd': {
      const cap = component.capacity || '';
      const iface = component.interface || '';
      return `${name}${addSpec(name, cap)}${addSpec(name, iface)}`.trim();
    }
    case 'psu': {
      const watt = component.watt ? `${component.watt}W` : '';
      const rating = component.rating || '';
      return `${name}${addSpec(name, watt)}${addSpec(name, rating)}`.trim();
    }
    case 'cooler': {
      const ctype = component.type || '';
      const tdp = component.tdpMax ? `${component.tdpMax}W TDP` : '';
      return `${name}${addSpec(name, ctype)}${addSpec(name, tdp)}`.trim();
    }
    case 'case': {
      const cff = component.formFactor || '';
      return `${name}${addSpec(name, cff)}`.trim();
    }
    default:
      return name;
  }
}

// Full compatibility check
export function fullCompatCheck(build) {
  const errors = [], warnings = [], ok = [];

  // 1. CPU + Motherboard socket check
  if (build.cpu && build.motherboard) {
    if (build.cpu.socket && build.motherboard.socket) {
      if (build.cpu.socket !== build.motherboard.socket) {
        errors.push(`سوكت المعالج (${build.cpu.socket}) غير متوافق مع اللوحة الأم (${build.motherboard.socket})`);
      } else {
        ok.push('سوكت المعالج متوافق مع اللوحة الأم ✓');
      }
    } else {
      warnings.push('لا يمكن التحقق من توافق السوكت — مواصفات ناقصة');
    }
  }

  // 2. RAM + Motherboard DDR type check
  if (build.ram && build.motherboard) {
    if (build.ram.type && build.motherboard.ramType) {
      if (build.ram.type !== build.motherboard.ramType) {
        errors.push(`الرام ${build.ram.type} غير متوافقة مع اللوحة الأم (${build.motherboard.ramType})`);
      } else {
        ok.push('نوع الرام متوافق مع اللوحة الأم ✓');
      }
    }
  }

  // 3. PSU wattage check — STRICT
  if (build.psu) {
    const needed = estimateWattage(build);
    const psuWatt = build.psu.watt || 0;
    if (psuWatt > 0 && psuWatt < needed) {
      errors.push(`الباور (${psuWatt}W) أقل من المطلوب (~${needed}W) — خطر على القطع!`);
    } else if (psuWatt > 0 && psuWatt < needed * 1.15) {
      warnings.push(`الباور (${psuWatt}W) يكفي بالكاد — يُفضل ${getRecommendedPSU(build)}W أو أعلى`);
    } else if (psuWatt > 0) {
      ok.push(`الباور كافي (${psuWatt}W لتجميعة ~${needed}W) ✓`);
    }
  }

  // 4. Cooler TDP check
  if (build.cpu && build.cooler) {
    const cpuTdp = build.cpu.tdp || 0;
    const coolerMax = build.cooler.tdpMax || 0;
    if (cpuTdp > 0 && coolerMax > 0 && coolerMax < cpuTdp) {
      warnings.push(`التبريد (${coolerMax}W) قد لا يكفي للمعالج (${cpuTdp}W TDP)`);
    } else if (cpuTdp > 0 && coolerMax > 0) {
      ok.push('التبريد كافي للمعالج ✓');
    }
  }

  // 5. Check for missing CRITICAL specs (custom/unknown parts)
  if (build.cpu && !build.cpu.socket) {
    warnings.push('المعالج بدون سوكت محدد — تحقق من التوافق يدوياً');
  }
  if (build.motherboard && !build.motherboard.socket) {
    warnings.push('اللوحة الأم بدون سوكت محدد — تحقق من التوافق يدوياً');
  }
  if (build.gpu && !build.gpu.tdp) {
    warnings.push('كرت الشاشة بدون TDP محدد — تحقق من الواط يدوياً');
  }
  if (build.psu && !build.psu.watt) {
    warnings.push('الباور بدون واط محدد — تحقق من كفاية الطاقة يدوياً');
  }

  // 6. If NO checks could be performed (all specs missing), warn
  if (errors.length === 0 && warnings.length === 0 && ok.length === 0) {
    warnings.push('لا توجد بيانات كافية لفحص التوافق');
  }

  return { errors, warnings, ok };
}
